    //         placeholder={current.placeholder}
    //         autoComplete="off"
    //         autoFocus
    //       />
    //     )}
    //     {current.type === 'date' && (
    //       <input
    //         id={`waterfall-${current.key}`}
    //         type="date"
    //         value={form[current.key]}
    //         onChange={(e) => setField(current.key, e.target.value)}
    //         autoFocus
    //       />
    //     )}
    //     {current.type === 'number' && (
    //       <input
    //         id={`waterfall-${current.key}`}
